import{_ as s,c as i,o as e,ag as p}from"./chunks/framework.D4Vqf8I7.js";const c=JSON.parse('{"title":"SAP","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/sap.md","filePath":"docs/wi/sap.md","lastUpdated":1777371752000}'),t={name:"docs/wi/sap.md"};function l(n,a,o,r,h,d){return e(),i("div",null,a[0]||(a[0]=[p(`<h1 id="sap" tabindex="-1">SAP <a class="header-anchor" href="#sap" aria-label="Permalink to &quot;SAP&quot;">​</a></h1><p><img src="https://upload.wikimedia.org/wikipedia/commons/thumb/5/59/SAP_2011_logo.svg/1280px-SAP_2011_logo.svg.png" alt=""></p><p>SAP SE — ведущая немецкая компания и одноименная система планирования ресурсов предприятия (ERP), предназначенная для автоматизации бизнес-процессов: финансов, логистики, HR и закупок. SAP объединяет все отделы компании в единую информационную среду. Компания занимает третье место в мире по разработке ПО.</p><h2 id="установка-и-проблема-с-java-неотредактировано-рыба" tabindex="-1">Установка и Проблема с Java (НЕОТРЕДАКТИРОВАНО, РЫБА) <a class="header-anchor" href="#установка-и-проблема-с-java-неотредактировано-рыба" aria-label="Permalink to &quot;Установка и Проблема с Java (НЕОТРЕДАКТИРОВАНО, РЫБА)&quot;">​</a></h2><p>Для исключения возможных проблем, переустановите систему с нуля, после чего обновите её до актуального состояния согласно документации.</p><p>В качестве библиотеки OpenJDK будем использовать Azul Zulu 21 с собранной JDK FX. Перейдите на сайт по данной ссылке и скачайте RPM пакет: <a href="https://www.azul.com/downloads/?version=java-21-lts&amp;os=linux&amp;architecture=arm-64-bit&amp;package=jdk-fx#zulu" target="_blank" rel="noreferrer">https://www.azul.com/downloads/?version=java-21-lts&amp;os=linux&amp;architecture=arm-64-bit&amp;package=jdk-fx#zulu</a> . По данной ссылке можно прочитать информацию о том, что сборка Azul OpenJDK является Open Source продуктом: <a href="https://www.azul.com/products/core/openjdk-terms-of-use/" target="_blank" rel="noreferrer">https://www.azul.com/products/core/openjdk-terms-of-use/</a></p><p>Установите скачанный пакет либо через графический установщик, либо с помощью команды:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./zulu21.44.17-ca-fx-jdk21.0.8-linux.x86_64.rpm</span></span></code></pre></div><p>Установите другие необходимые пакеты стандартным образом.</p><div class="warning custom-block"><p class="custom-block-title">ВНИМАНИЕ</p><p>openjdk, openjfx и прочее устанавливать не нужно.</p></div><p>Проблема заключается в том, что SAP GUI запрашивает путь до JVM, определенный в переменной окружения <code>$JAVA_HOME</code>. По умолчанию она хранит значение <code>/usr/lib/jvm/jre</code>. <code>/usr/lib/jvm/jre</code> - это символическая ссылка, которая по умолчанию ведёт к <code>/usr/lib/jvm/java-21-openjdk-21.0.8.0.9-alt2.aarch64</code></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Если запуск SAP GUI производится через терминал, вы можете, для тестирования, переопределить переменную окружения <code>$JAVA_HOME</code>. Работать это будет в рамках данной терминальной сессии:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> JAVA_HOME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/usr/lib/jvm/java-21-zulu-openjdk-jdk-fx </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># убедитесь, что путь до zulu openjdk верный</span></span></code></pre></div><p>После чего попробуйте запустить SAP GUI.</p><p>Если всё работает корректно, то Вы можете либо отредактировать символическую ссылке <code>/usr/lib/jvm/jre</code>, либо добавить export, которые Вы делали выше, в файл <code>~/.bash_profile</code>. Далее нужно перезагрузить компьютер, после чего переменная <code>$JAVA_HOME</code> для данного пользователя будет иметь указанное значение.</p><p>Если же вы хотите, чтобы эта переменная переопределялась для всех пользователей в системе, тогда необходимо данный export поместить в конец файла <code>/etc/profile</code>.</p></div><p>Радикальные методы:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/lib/jvm/jre</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/lib/jvm/java-21-zulu-openjdk-jdk-fx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/lib/jvm/jre</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> убедитесь,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> что</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> путь</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> до</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zulu</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> верный</span></span></code></pre></div><p>Новая проблема, вероятнее всего, заключается в том, что SAP GUI использует Nashorn — JavaScript-движок, который был встроен в JDK до версии 14. В JDK 15+ Nashorn полностью удалён.</p><p>В связи с этим, попробуйте установить 11 версию OpenJDK: <a href="https://www.azul.com/downloads/?version=java-11-lts&amp;os=linux&amp;architecture=arm-64-bit&amp;package=jdk-fx#zulu" target="_blank" rel="noreferrer">https://www.azul.com/downloads/?version=java-11-lts&amp;os=linux&amp;architecture=arm-64-bit&amp;package=jdk-fx#zulu</a></p><p>Как мне кажется, SAP вооще сделан под Java 7.8</p><p>Далее, попробуйте установить SAP GUI</p>`,18)]))}const u=s(t,[["render",l]]);export{c as __pageData,u as default};
